operations.reducer:
if (action.input.title) state.title = action.input.title;
if (action.input.body) state.body = action.input.body;
if (action.input.visibility) state.visibility = action.input.visibility;
if (action.input.authorProfileId) state.authorProfileId = action.input.authorProfileId;

operations.schema:
input DraftUpdateInput {
    title: String
    body: String
    visibility: UpdateVisibility
    authorProfileId: PHID
}

input EditUpdateInput {
    title: String
    body: String
}

operations.reducer:
if (state.publishedAt) throw new UpdateAlreadyPublishedError('Update has already been published');
if (!state.title || !state.body) throw new MissingTitleOrBodyError('Title and body are required to publish');
state.publishedAt = action.input.publishedAt;
if (action.input.metricsSnapshot) {
  state.metricsSnapshot = {
    totalPledged: action.input.metricsSnapshot.totalPledged ?? null,
    totalReceived: action.input.metricsSnapshot.totalReceived ?? null,
    dependenciesResolved: action.input.metricsSnapshot.dependenciesResolved ?? null,
  };
}

operations.schema:
input MetricsSnapshotInput {
    totalPledged: Amount_Tokens
    totalReceived: Amount_Tokens
    dependenciesResolved: Int
}

input PublishUpdateInput {
    publishedAt: DateTime!
    metricsSnapshot: MetricsSnapshotInput
}

operations.reducer:
state.externalAnnouncements.push({
  id: action.input.id,
  platform: action.input.platform,
  url: action.input.url,
});

operations.schema:
input AttachAnnouncementInput {
    id: OID!
    platform: AnnouncementPlatform!
    url: URL!
}

global.schema:
type StatusUpdateState {
    publishedAt: DateTime
    visibility: UpdateVisibility!
    authorProfileId: PHID
    title: String!
    body: String!
    metricsSnapshot: MetricsSnapshot
    externalAnnouncements: [ExternalAnnouncement!]!
}

enum UpdateVisibility {
    PUBLIC
    CONTRIBUTORS_ONLY
    INTERNAL
}

enum AnnouncementPlatform {
    TWITTER
    FARCASTER
    MIRROR
    BLOG
}

type MetricsSnapshot {
    totalPledged: Amount_Tokens
    totalReceived: Amount_Tokens
    dependenciesResolved: Int
}

type ExternalAnnouncement {
    id: OID!
    platform: AnnouncementPlatform!
    url: URL!
}
